const body = $json.body || $json;
const draft_id = body.draft_id;
const site_id = body.site_id;

if (!draft_id) {
  return [{ json: { error: true, message: 'draft_id is required' } }];
}

// Call the Generator's approve endpoint to actually update staticData
const resp = await fetch('https://n8n.sinabarimd.com/webhook/approve-draft-gen', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({ draft_id, site_id }),
});
const result = await resp.json();
return [{ json: result }];

// draft data comes from Generator's get-draft webhook
const draft = $json;
const site_id = draft.site_id;
const article = draft.article;
const draft_id = draft.draft_id || `manual_${Date.now()}`;

if (!site_id) throw new Error('site_id is required');
if (!article?.title) throw new Error('article.title is required [from get-draft response]');
if (!article?.content_html) throw new Error('article.content_html is required');

const DOMAINS   = { sinabarimd: 'sinabarimd.com', sinabari_net: 'sinabari.net', drsinabari: 'drsinabari.com', sinabariplasticsurgery: 'sinabariplasticsurgery.com' };
const LIVE_URLS = { sinabarimd: 'https://sinabarimd.com', sinabari_net: 'https://sinabari.net', drsinabari: 'https://drsinabari.com', sinabariplasticsurgery: 'https://sinabariplasticsurgery.com' };
const SECTIONS  = { sinabarimd: 'PUBLICATIONS', sinabari_net: 'ANALYSIS', drsinabari: 'ESSAYS', sinabariplasticsurgery: 'ARTICLES' };
const DEPLOY_PATHS = { sinabarimd: '/srv/sites/sinabarimd', sinabari_net: '/srv/sites/sinabari-net', drsinabari: '/srv/sites/drsinabari', sinabariplasticsurgery: '/srv/sites/sinabariplasticsurgery' };

return [{ json: {
  site_id, draft_id, domain: DOMAINS[site_id], live_url: LIVE_URLS[site_id],
  section: SECTIONS[site_id], deploy_path: DEPLOY_PATHS[site_id], article,
} }];

const staticData = $getWorkflowStaticData('global');
const fields = $('Extract Publish Fields').first().json;
const { site_id, article } = fields;
const pageHtml = $json.data || $json.body || '';

if (!staticData.article_register) staticData.article_register = {};
const register = staticData.article_register[site_id] || [];

// Build article entry
const slug = article.slug || article.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');
const entry = {
  slug,
  title: article.title,
  excerpt: article.excerpt || '',
  date: article.date || new Date().toISOString().split('T')[0],
  url: `/articles/${slug}.html`,
  content_html: article.content_html,
  author: article.author || 'Dr. Sina Bari, MD',
  author_url: article.author_url || 'https://sinabarimd.com/about',
};

// Prepend, cap at 3
const updated = [entry, ...register.filter(a => a.slug !== slug)].slice(0, 3);
staticData.article_register[site_id] = updated;

// Fetch ALL pinned spotlight articles (current + history) for inclusion in index + deploy
let pinned_articles = [];
try {
  const spResp = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://n8n.sinabarimd.com/webhook/spotlight',
    returnFullResponse: true,
    encoding: 'utf-8',
    timeout: 5000,
  });
  const spData = typeof spResp.body === 'string' ? JSON.parse(spResp.body) : spResp.body;
  if (site_id === 'sinabarimd') {
    // Current spotlight
    if (spData?.spotlight?.slug) {
      const sp = spData.spotlight;
      if (!updated.some(a => a.slug === sp.slug)) {
        pinned_articles.push({
          slug: sp.slug, title: sp.title, excerpt: sp.excerpt || '',
          date: sp.publish_date || new Date().toISOString().split('T')[0],
          url: '/articles/' + sp.slug + '.html',
          pinned: true, is_current_spotlight: true,
        });
      }
    }
    // All historical spotlights
    for (const h of (spData.history || [])) {
      if (h.slug && !updated.some(a => a.slug === h.slug) && !pinned_articles.some(p => p.slug === h.slug)) {
        pinned_articles.push({
          slug: h.slug, title: h.title, excerpt: h.excerpt || '',
          date: h.publish_date || '',
          url: '/articles/' + h.slug + '.html',
          pinned: true,
        });
      }
    }
  }
} catch(e) { /* spotlight not set */ }

return [{ json: { ...fields, page_html: pageHtml, article_register: updated, pinned_articles } }];

const { section, rendered_section } = $json;
let html = $json.page_html;

const startMark = `<!-- PIPELINE:START:${section} -->`;
const endMark   = `<!-- PIPELINE:END:${section} -->`;

const s = html.indexOf(startMark);
const e = html.indexOf(endMark);

if (s < 0 || e < 0) throw new Error(`PIPELINE markers not found for section ${section}`);

const newHtml = html.slice(0, s + startMark.length) + '\n' + rendered_section + '\n' + html.slice(e);
return [{ json: { ...$json, updated_html: newHtml } }];

const { site_id, domain, live_url, article, article_register } = $json;
const a = article;
const slug = a.slug || a.title.toLowerCase().replace(/[^a-z0-9]+/g,'-').replace(/^-|-$/g,'');
const fmt = (d) => { try { return new Date(d).toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'}); } catch(e){return d;} };
const isoDate = (d) => { try { return new Date(d).toISOString(); } catch(e){return d;} };

// Determine article number
const register = article_register || [];
const num = register.findIndex(r => r.slug === slug) + 1 || 1;

// Site-specific styling tokens
const STYLES = {
  sinabariplasticsurgery: { bg:'#faf9f7', accent:'#6b8f6e', font:'Newsreader, Georgia, serif', label:'Education', navBrand:'Dr. Sina Bari, MD', siteName:'Dr. Sina Bari, MD — Plastic Surgery' },
  sinabari_net:  { bg:'#0f1117', accent:'#4db6ac', font:'Inter, sans-serif', label:'Analysis', navBrand:'Sina Bari', siteName:'Sina Bari — Healthcare AI' },
  sinabarimd:    { bg:'#efeeeb', accent:'#001a2b', font:'Cormorant Garamond, Georgia, serif', label:'Publication', navBrand:'Sina Bari, MD', siteName:'Sina Bari, MD' },
  drsinabari:    { bg:'#fefefe', accent:'#1a1a1a', font:'Lora, Georgia, serif', label:'Essay', navBrand:'Dr. Sina Bari', siteName:'Dr. Sina Bari' },
};

// Per-site author byline blurbs
const AUTHOR_BIOS = {
  sinabarimd: 'Dr. Sina Bari, MD is a plastic and reconstructive surgeon and medical executive. Stanford-trained physician dedicated to advancing healthcare through clinical excellence and strategic leadership.',
  sinabari_net: 'Dr. Sina Bari, MD is a physician-technologist and healthcare AI executive. Stanford-trained physician specializing in the intersection of clinical medicine and technology.',
  sinabariplasticsurgery: 'Dr. Sina Bari, MD is a plastic and reconstructive surgeon trained at Stanford, specializing in aesthetic and reconstructive procedures.',
  drsinabari: 'Dr. Sina Bari is a physician, writer, and medical executive exploring the intersection of medicine, technology, and society.',
};

// Per-site credential context for byline header
const AUTHOR_CREDENTIALS = {
  sinabarimd: 'Plastic & Reconstructive Surgeon | Medical Executive | Stanford Medicine',
  sinabari_net: 'Physician-Technologist | Healthcare AI Executive | Stanford Medicine',
  sinabariplasticsurgery: 'Plastic & Reconstructive Surgeon | Stanford-trained | California',
  drsinabari: 'Physician | Writer | Medical Executive | Stanford Medicine',
};

// Cross-site links (exclude current site)
const SITE_LINKS = {
  sinabarimd: { url: 'https://sinabarimd.com', label: 'Dr. Sina Bari, MD' },
  sinabari_net: { url: 'https://sinabari.net', label: 'Healthcare AI Analysis' },
  drsinabari: { url: 'https://drsinabari.com', label: 'Essays & Editorial' },
  sinabariplasticsurgery: { url: 'https://sinabariplasticsurgery.com', label: 'Surgical Education' },
};

const s = STYLES[site_id] || STYLES.sinabariplasticsurgery;
const isDark = site_id === 'sinabari_net';
const textColor = isDark ? '#e0e0e0' : '#1c1b1f';
const mutedColor = isDark ? '#aaa' : '#555';

// Per-site article @type
const articleType = site_id === 'sinabariplasticsurgery' ? 'MedicalWebPage' : 'Article';
const authorName = a.author || 'Dr. Sina Bari, MD';

// ── Extract FAQ pairs from content_html ──
const faqPairs = [];
const faqPatterns = [
  /<p>\s*<strong>([^<]+\?)\s*<\/strong>\s*(?:<br\s*\/?>)?\s*([\s\S]*?)<\/p>/gi,
  /<h3>([^<]+\?)\s*<\/h3>\s*<p>([\s\S]*?)<\/p>/gi,
];
const contentHtml = a.content_html || '';
for (const pattern of faqPatterns) {
  let match;
  while ((match = pattern.exec(contentHtml)) !== null) {
    const question = match[1].trim();
    const answer = match[2].replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
    if (question && answer && !faqPairs.find(f => f.q === question)) {
      faqPairs.push({ q: question, a: answer });
    }
  }
}

// ── Build Article schema (enhanced with reviewedBy + lastReviewed) ──
const publishDate = isoDate(a.date);
const schema = {
  "@context": "https://schema.org",
  "@type": articleType,
  "@id": `${live_url}/articles/${slug}.html#article`,
  "headline": a.title,
  "description": a.excerpt,
  "datePublished": publishDate,
  "dateModified": publishDate,
  "dateReviewed": publishDate,
  "url": `${live_url}/articles/${slug}.html`,
  "inLanguage": "en-US",
  "mainEntityOfPage": {
    "@type": "WebPage",
    "@id": `${live_url}/articles/${slug}.html`
  },
  "isPartOf": {
    "@type": "WebSite",
    "@id": `${live_url}/#website`,
    "name": s.siteName
  },
  "author": {
    "@type": "Person",
    "@id": "https://sinabarimd.com/#sinabari",
    "name": authorName,
    "url": "https://sinabarimd.com/about",
    "qualifications": "MD",
    "alumniOf": { "@type": "EducationalOrganization", "name": "Stanford University School of Medicine" }
  },
  "publisher": {
    "@type": "Person",
    "@id": "https://sinabarimd.com/#sinabari",
    "name": "Dr. Sina Bari, MD",
    "url": "https://sinabarimd.com/about"
  },
  "reviewedBy": {
    "@type": "Person",
    "@id": "https://sinabarimd.com/#sinabari",
    "name": "Dr. Sina Bari, MD",
    "qualifications": "MD"
  }
};

// ── Build FAQPage schema if FAQ pairs found ──
let faqSchemaBlock = '';
if (faqPairs.length >= 2) {
  const faqSchema = {
    "@context": "https://schema.org",
    "@type": "FAQPage",
    "mainEntity": faqPairs.map(f => ({
      "@type": "Question",
      "name": f.q,
      "acceptedAnswer": {
        "@type": "Answer",
        "text": f.a
      }
    }))
  };
  faqSchemaBlock = `\n  <script type="application/ld+json">\n  ${JSON.stringify(faqSchema, null, 2)}\n  </script>`;
}

// ── Build cross-site links (exclude current) ──
const crossLinks = Object.entries(SITE_LINKS)
  .filter(([id]) => id !== site_id)
  .map(([id, info]) => `<a href="${info.url}" style="font-size:0.75rem;color:${mutedColor};text-decoration:none;border-bottom:1px solid ${s.accent}22;padding-bottom:2px;">${info.label}</a>`)
  .join('<span style="margin:0 0.75rem;color:' + s.accent + '33;">|</span>');

const articlePageHtml = `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>${a.title} | ${s.navBrand}</title>
  <meta name="description" content="${a.excerpt}"/>
  <meta name="author" content="${authorName}"/>
  <meta name="robots" content="index, follow"/>
  <link rel="canonical" href="${live_url}/articles/${slug}.html"/>
  <meta property="og:type" content="article"/>
  <meta property="og:title" content="${a.title}"/>
  <meta property="og:description" content="${a.excerpt}"/>
  <meta property="og:url" content="${live_url}/articles/${slug}.html"/>
  <meta property="og:site_name" content="${s.siteName}"/>
  <meta property="article:published_time" content="${publishDate}"/>
  <meta property="article:author" content="https://sinabarimd.com/about"/>
  <meta name="twitter:card" content="summary"/>
  <meta name="twitter:title" content="${a.title}"/>
  <meta name="twitter:description" content="${a.excerpt}"/>
  <script src="https://cdn.tailwindcss.com?plugins=forms,container-queries"></script>
  <link href="https://fonts.googleapis.com/css2?family=${s.font.split(',')[0].trim().replace(/ /,'+')}:ital,wght@0,400;0,700;1,400&display=swap" rel="stylesheet"/>
  <link href="https://fonts.googleapis.com/icon?family=Material+Icons+Outlined" rel="stylesheet"/>
  <style>
    body { background: ${s.bg}; color: ${textColor}; font-family: ${s.font}; }
    .article-prose h2 { font-family: ${s.font}; font-size: 1.875rem; line-height: 1.25; margin-top: 3rem; margin-bottom: 1rem; color: ${textColor}; }
    .article-prose h3 { font-family: ${s.font}; font-size: 1.375rem; line-height: 1.3; margin-top: 2rem; margin-bottom: 0.75rem; color: ${textColor}; }
    .article-prose p  { font-size: 1.125rem; line-height: 1.85; margin-bottom: 1.5rem; color: ${mutedColor}; }
    .article-prose a  { color: ${s.accent}; border-bottom: 1px solid ${s.accent}; text-decoration: none; }
    .article-prose a:hover { opacity: 0.7; }
    .article-prose em { font-style: italic; font-size: 0.9rem; color: ${mutedColor}; }
    .accent { color: ${s.accent}; }
    .accent-border { border-color: ${s.accent}; }
    .accent-bg { background: ${s.accent}; }
  </style>
  <script type="application/ld+json">
  ${JSON.stringify(schema, null, 2)}
  </script>${faqSchemaBlock}
</head>
<body>
  <nav style="background:${s.bg};border-bottom:1px solid ${s.accent}22;position:fixed;top:0;left:0;right:0;z-index:50;backdrop-filter:blur(8px);">
    <div style="max-width:1200px;margin:0 auto;padding:1rem 1.5rem;display:flex;justify-content:space-between;align-items:center;">
      <a href="/" style="font-family:${s.font};font-size:1.1rem;color:${textColor};text-decoration:none;font-weight:600;">${s.navBrand}</a>
      <a href="/articles/" style="font-size:0.7rem;letter-spacing:0.15em;text-transform:uppercase;color:${mutedColor};text-decoration:none;">\u2190 Journal</a>
    </div>
  </nav>

  <header style="max-width:820px;margin:0 auto;padding:8rem 1.5rem 3rem;">
    <div style="margin-bottom:1.5rem;">
      <span style="font-size:0.65rem;letter-spacing:0.2em;text-transform:uppercase;color:${s.accent};">${s.label} / 00${num}</span>
    </div>
    <h1 style="font-family:${s.font};font-size:clamp(2rem,5vw,3.5rem);line-height:1.2;margin-bottom:1.5rem;color:${textColor};">${a.title}</h1>
    <p style="font-size:1.2rem;line-height:1.7;color:${mutedColor};margin-bottom:2.5rem;max-width:600px;">${a.excerpt}</p>
    <div style="display:flex;flex-wrap:wrap;align-items:center;gap:2rem;border-top:1px solid ${s.accent}33;padding-top:2rem;">
      <div>
        <p style="font-size:0.65rem;letter-spacing:0.15em;text-transform:uppercase;color:${mutedColor};margin-bottom:0.25rem;">Author</p>
        <a href="https://sinabarimd.com/about" style="font-family:${s.font};font-size:1.1rem;color:${textColor};text-decoration:none;">${authorName}</a>
        <p style="font-size:0.75rem;color:${mutedColor};margin:0.25rem 0 0 0;">${AUTHOR_CREDENTIALS[site_id] || AUTHOR_CREDENTIALS.sinabarimd}</p>
      </div>
      <div style="width:1px;height:2rem;background:${s.accent}33;"></div>
      <div>
        <p style="font-size:0.65rem;letter-spacing:0.15em;text-transform:uppercase;color:${mutedColor};margin-bottom:0.25rem;">Published</p>
        <p style="font-family:${s.font};font-size:1.1rem;color:${textColor};margin:0;">${fmt(a.date)}</p>
      </div>
      <div style="width:1px;height:2rem;background:${s.accent}33;"></div>
      <div>
        <p style="font-size:0.65rem;letter-spacing:0.15em;text-transform:uppercase;color:${mutedColor};margin-bottom:0.25rem;">Reviewed</p>
        <p style="font-family:${s.font};font-size:0.9rem;color:${textColor};margin:0;">${fmt(a.date)}</p>
      </div>
    </div>
  </header>

  <main style="max-width:820px;margin:0 auto;padding:0 1.5rem 6rem;">
    <div class="article-prose">${a.content_html}</div>
  </main>

  <aside style="max-width:820px;margin:0 auto;padding:0 1.5rem 3rem;">
    <div style="border-top:1px solid ${s.accent}22;padding-top:2rem;display:flex;gap:1.25rem;align-items:flex-start;">
      <div style="min-width:48px;width:48px;height:48px;border-radius:50%;background:${s.accent}15;display:flex;align-items:center;justify-content:center;">
        <span style="font-family:${s.font};font-size:1.1rem;font-weight:600;color:${s.accent};">SB</span>
      </div>
      <div>
        <a href="https://sinabarimd.com/about" style="font-family:${s.font};font-size:1.05rem;font-weight:600;color:${textColor};text-decoration:none;">Dr. Sina Bari, MD</a>
        <p style="font-size:0.75rem;color:${mutedColor};margin:0.15rem 0 0.35rem 0;">${AUTHOR_CREDENTIALS[site_id] || AUTHOR_CREDENTIALS.sinabarimd}</p>
        <p style="font-size:0.85rem;line-height:1.6;color:${mutedColor};margin-top:0.35rem;margin-bottom:0;">${AUTHOR_BIOS[site_id] || AUTHOR_BIOS.sinabarimd}</p>
      </div>
    </div>
  </aside>

  <footer style="border-top:1px solid ${s.accent}22;padding:3rem 1.5rem;">
    <div style="max-width:1200px;margin:0 auto;">
      <div style="display:flex;flex-wrap:wrap;justify-content:center;gap:0;margin-bottom:2rem;">
        ${crossLinks}
      </div>
      <div style="display:flex;flex-wrap:wrap;justify-content:space-between;align-items:center;gap:1rem;">
        <p style="font-size:0.65rem;letter-spacing:0.15em;text-transform:uppercase;color:${mutedColor};">${s.navBrand} &mdash; ${domain}</p>
        <a href="https://sinabarimd.com" style="font-size:0.65rem;letter-spacing:0.15em;text-transform:uppercase;color:${s.accent};text-decoration:none;">sinabarimd.com</a>
      </div>
    </div>
  </footer>
</body>
</html>`;

return [{ json: { ...$json, article_page_html: articlePageHtml, article_slug: slug, faq_count: faqPairs.length } }];

const { updated_html, article_page_html, site_id, article, section } = $json;
const errors = [];
const warnings = [];
const slug = $json.article_slug;

if (!updated_html.includes(`PIPELINE:START:${section}`)) errors.push('PIPELINE start marker missing from homepage');
if (!updated_html.includes(`PIPELINE:END:${section}`)) errors.push('PIPELINE end marker missing from homepage');
if (!updated_html.includes(slug)) errors.push(`Article slug not found in homepage: ${slug}`);
if (!article_page_html.includes(article.title)) errors.push('Title missing from article page');
if (site_id !== 'sinabarimd' && !article_page_html.includes('sinabarimd.com')) errors.push('Missing sinabarimd.com link in article page');

// Outbound source link check (warning, not blocker)
const externalLinkPattern = /href=["']https?:\/\/(?!sinabarimd\.com|sinabari\.net|sinabariplasticsurgery\.com|drsinabari\.com)[^"']+["']/gi;
const externalLinks = (article_page_html || '').match(externalLinkPattern) || [];
if (externalLinks.length === 0) {
  warnings.push('No outbound source links found in article. Articles should include 2-3 external authority links for E-E-A-T signals.');
}

if (errors.length > 0) throw new Error(`QA failed: ${errors.join('; ')}`);
return [{ json: { ...$json, qa_passed: true, qa_warnings: warnings, outbound_link_count: externalLinks.length } }];

const { site_id, domain, deploy_path, live_url, updated_html, article_page_html, article_slug, articles_index_html, styles_css, article_register } = $json;

const files = [
  { path: 'index.html', content: updated_html },
  { path: `articles/${article_slug}.html`, content: article_page_html },
  { path: 'articles/index.html', content: articles_index_html },
];

// CRITICAL: Fetch ALL existing article pages to preserve them during full-sync deploy
const existingArticles = article_register || [];
for (const article of existingArticles) {
  if (article.slug && article.slug !== article_slug) {
    try {
      const existingPage = await this.helpers.httpRequest({
        method: 'GET',
        url: `${live_url}/articles/${article.slug}.html`,
        returnFullResponse: true,
        encoding: 'utf-8',
        timeout: 10000,
      });
      if (existingPage && existingPage.body && existingPage.body.length > 500 && existingPage.statusCode === 200) {
        files.push({ path: `articles/${article.slug}.html`, content: existingPage.body });
      }
    } catch (e) {
      // Article may not exist yet — skip silently
    }
  }
}
if (styles_css && styles_css.length > 10) {
  files.push({ path: 'styles.css', content: styles_css });
}

// Generate sitemap from register
const today = new Date().toISOString().split('T')[0];
const register = article_register || [];
const SITE_PAGES = {
  sinabarimd: ['/', '/about.html', '/press.html', '/articles/'],
  sinabari_net: ['/', '/articles/'],
  sinabariplasticsurgery: ['/', '/articles/'],
};
const staticPages = SITE_PAGES[site_id] || ['/', '/articles/'];

let sitemap = '<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n';
for (const p of staticPages) {
  const pri = p === '/' ? '1.0' : '0.8';
  sitemap += `  <url><loc>${live_url}${p}</loc><lastmod>${today}</lastmod><priority>${pri}</priority></url>\n`;
}
for (const a of register) {
  if (a.slug) sitemap += `  <url><loc>${live_url}/articles/${a.slug}.html</loc><lastmod>${a.date || today}</lastmod><priority>0.8</priority></url>\n`;
}
sitemap += '</urlset>';
files.push({ path: 'sitemap.xml', content: sitemap });
files.push({ path: 'robots.txt', content: `User-agent: *\nAllow: /\n\nSitemap: ${live_url}/sitemap.xml\n` });

// For sinabarimd.com: preserve dashboard, about, press pages
if (site_id === 'sinabarimd') {
  const extraPaths = ['dashboard.html', 'about.html', 'press.html'];
  for (const ep of extraPaths) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: `${live_url}/${ep}`,
        returnFullResponse: true,
        encoding: 'utf-8',
      });
      if (resp && resp.body && resp.body.length > 100) {
        files.push({ path: ep, content: resp.body });
      }
    } catch (e) {
      // File might not exist — skip silently
    }
  }
}


// For sinabarimd.com: include ALL spotlight articles (current + history)
if (site_id === 'sinabarimd') {
  try {
    const spotlightResp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://n8n.sinabarimd.com/webhook/spotlight',
      returnFullResponse: true,
      encoding: 'utf-8',
