const { updated_html, article_page_html, site_id, article, section } = $json;
const errors = [];
const warnings = [];
const slug = $json.article_slug;

if (!updated_html.includes(`PIPELINE:START:${section}`)) errors.push('PIPELINE start marker missing from homepage');
if (!updated_html.includes(`PIPELINE:END:${section}`)) errors.push('PIPELINE end marker missing from homepage');
if (!updated_html.includes(slug)) errors.push(`Article slug not found in homepage: ${slug}`);
if (!article_page_html.includes(article.title)) errors.push('Title missing from article page');
if (site_id !== 'sinabarimd' && !article_page_html.includes('sinabarimd.com')) errors.push('Missing sinabarimd.com link in article page');

// Outbound source link check (warning, not blocker)
const externalLinkPattern = /href=["']https?:\/\/(?!sinabarimd\.com|sinabari\.net|sinabariplasticsurgery\.com|drsinabari\.com)[^"']+["']/gi;
const externalLinks = (article_page_html || '').match(externalLinkPattern) || [];
if (externalLinks.length === 0) {
  warnings.push('No outbound source links found in article. Articles should include 2-3 external authority links for E-E-A-T signals.');
}

if (errors.length > 0) throw new Error(`QA failed: ${errors.join('; ')}`);
return [{ json: { ...$json, qa_passed: true, qa_warnings: warnings, outbound_link_count: externalLinks.length } }];

const { site_id, domain, deploy_path, live_url, updated_html, article_page_html, article_slug, articles_index_html, styles_css, article_register } = $json;

const files = [
  { path: 'index.html', content: updated_html },
  { path: `articles/${article_slug}.html`, content: article_page_html },
  { path: 'articles/index.html', content: articles_index_html },
];

// CRITICAL: Fetch ALL existing article pages to preserve them during full-sync deploy
const existingArticles = article_register || [];
for (const article of existingArticles) {
  if (article.slug && article.slug !== article_slug) {
    try {
      const existingPage = await this.helpers.httpRequest({
        method: 'GET',
        url: `${live_url}/articles/${article.slug}.html`,
        returnFullResponse: true,
        encoding: 'utf-8',
        timeout: 10000,
      });
      if (existingPage && existingPage.body && existingPage.body.length > 500 && existingPage.statusCode === 200) {
        files.push({ path: `articles/${article.slug}.html`, content: existingPage.body });
      }
    } catch (e) {
      // Article may not exist yet — skip silently
    }
  }
}
if (styles_css && styles_css.length > 10) {
  files.push({ path: 'styles.css', content: styles_css });
}

// Generate sitemap from register
const today = new Date().toISOString().split('T')[0];
const register = article_register || [];
const SITE_PAGES = {
  sinabarimd: ['/', '/about.html', '/press.html', '/articles/'],
  sinabari_net: ['/', '/articles/'],
  sinabariplasticsurgery: ['/', '/articles/'],
};
const staticPages = SITE_PAGES[site_id] || ['/', '/articles/'];

let sitemap = '<?xml version="1.0" encoding="UTF-8"?>\n<urlset xmlns="http://www.sitemaps.org/schemas/sitemap/0.9">\n';
for (const p of staticPages) {
  const pri = p === '/' ? '1.0' : '0.8';
  sitemap += `  <url><loc>${live_url}${p}</loc><lastmod>${today}</lastmod><priority>${pri}</priority></url>\n`;
}
for (const a of register) {
  if (a.slug) sitemap += `  <url><loc>${live_url}/articles/${a.slug}.html</loc><lastmod>${a.date || today}</lastmod><priority>0.8</priority></url>\n`;
}
sitemap += '</urlset>';
files.push({ path: 'sitemap.xml', content: sitemap });
files.push({ path: 'robots.txt', content: `User-agent: *\nAllow: /\n\nSitemap: ${live_url}/sitemap.xml\n` });

// For sinabarimd.com: preserve dashboard, about, press pages
if (site_id === 'sinabarimd') {
  const extraPaths = ['dashboard.html', 'about.html', 'press.html'];
  for (const ep of extraPaths) {
    try {
      const resp = await this.helpers.httpRequest({
        method: 'GET',
        url: `${live_url}/${ep}`,
        returnFullResponse: true,
        encoding: 'utf-8',
      });
      if (resp && resp.body && resp.body.length > 100) {
        files.push({ path: ep, content: resp.body });
      }
    } catch (e) {
      // File might not exist — skip silently
    }
  }
}


// For sinabarimd.com: include ALL spotlight articles (current + history)
if (site_id === 'sinabarimd') {
  try {
    const spotlightResp = await this.helpers.httpRequest({
      method: 'GET',
      url: 'https://n8n.sinabarimd.com/webhook/spotlight',
      returnFullResponse: true,
      encoding: 'utf-8',
      timeout: 5000,
    });
    const spotlightData = typeof spotlightResp.body === 'string' ? JSON.parse(spotlightResp.body) : spotlightResp.body;
    // Current spotlight
    if (spotlightData?.spotlight?.article_html && spotlightData.spotlight.article_path) {
      const sp = spotlightData.spotlight;
      files.push({ path: sp.article_path, content: sp.article_html });
      sitemap = sitemap.replace('</urlset>', `  <url><loc>${live_url}/${sp.article_path}</loc><lastmod>${sp.publish_date || today}</lastmod><priority>0.9</priority></url>\n</urlset>`);
    }
    // Historical spotlights
    for (const h of (spotlightData.history || [])) {
      if (h.article_html && h.slug) {
        const hPath = 'articles/' + h.slug + '.html';
        if (!files.some(f => f.path === hPath)) {
          files.push({ path: hPath, content: h.article_html });
          sitemap = sitemap.replace('</urlset>', `  <url><loc>${live_url}/${hPath}</loc><lastmod>${h.publish_date || today}</lastmod><priority>0.8</priority></url>\n</urlset>`);
        }
      }
    }
    // Update sitemap in files
    const smIdx = files.findIndex(f => f.path === 'sitemap.xml');
    if (smIdx >= 0) files[smIdx].content = sitemap;
  } catch (e) {
    // Spotlight not set or fetch failed
  }
}

const deploy_payload = {
  domain, deployPath: deploy_path, verifyUrl: live_url,
  release_id: `rel_${Date.now()}`,
  files,
};
return [{ json: { ...$json, deploy_payload, deploy_payload_str: JSON.stringify(deploy_payload) } }];

